#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int first = 1; // flag to control leading spaces
        for (int i = 0; i < N; ++i) {
            int x;
            scanf("%d", &x);
            if (x <= 10) {
                if (!first) printf(" ");
                printf("%d", x * x);
                first = 0;
            }
        }
        printf("\n");
    }
    return 0;
}

